/**
 * Yo Soy James - Spiritual Landing Page
 * Smooth scroll, fade-in animations, and interactions
 */

document.addEventListener('DOMContentLoaded', () => {
    initSmoothScroll();
    initScrollAnimations();
});

/**
 * Smooth scroll for anchor links
 */
function initSmoothScroll() {
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function (e) {
            const href = this.getAttribute('href');
            if (href === '#') return;
            
            const target = document.querySelector(href);
            if (target) {
                e.preventDefault();
                target.scrollIntoView({
                    behavior: 'smooth',
                    block: 'start'
                });
            }
        });
    });
}

/**
 * Fade-in animations on scroll using Intersection Observer
 */
function initScrollAnimations() {
    const sections = document.querySelectorAll('.section-fade');
    
    const observerOptions = {
        root: null,
        rootMargin: '0px 0px -80px 0px', // Trigger slightly before section enters viewport
        threshold: 0.1
    };

    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add('visible');
            }
        });
    }, observerOptions);

    sections.forEach(section => {
        observer.observe(section);
    });
} 

function initFloatWhatsApp() {
    const floatWhatsApp = document.querySelector('.float-whatsapp');
    if (floatWhatsApp) {
        floatWhatsApp.addEventListener('click', () => {
            window.open('https://wa.me/5212222222222', '_blank');
        });
    }
}
